#!/usr/bin/env python3\n\"\"\"\nLocal Testing Script for Traffic Management System\nRun this before deploying to Vercel\n\"\"\"\n\nimport os\nimport sys\nimport subprocess\n\ndef run_command(cmd, description):\n    \"\"\"Run a command and report results\"\"\"\n    print(f\"\\n{'='*60}\")\n    print(f\"вћ¤ {description}\")\n    print(f\"{'='*60}\")\n    result = subprocess.run(cmd, shell=True)\n    return result.returncode == 0\n\ndef main():\n    print(\"\"\"\nв•”в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•—\nв•‘     рџљ¦ Traffic Management System - Local Test Suite        в•‘\nв•љв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ќ\n    \"\"\")\n    \n    # Check Python version\n    if sys.version_info < (3, 8):\n        print(\"вќЊ Python 3.8+ required\")\n        return 1\n    \n    print(f\"вњ… Python {sys.version_info.major}.{sys.version_info.minor}\")\n    \n    # Check dependencies\n    print(\"\\nрџ“¦ Checking dependencies...\")\n    required = ['flask', 'cv2', 'ultralytics', 'numpy']\n    missing = []\n    \n    for pkg in required:\n        try:\n            __import__(pkg)\n            print(f\"  вњ… {pkg}\")\n        except ImportError:\n            print(f\"  вќЊ {pkg}\")\n            missing.append(pkg)\n    \n    if missing:\n        print(f\"\\nвљ пёЏ  Missing: {', '.join(missing)}\")\n        print(\"\\nрџ’Ў Run: pip install -r requirements.txt\")\n        return 1\n    \n    # Check folder structure\n    print(\"\\nрџ“Ѓ Checking folder structure...\")\n    folders = ['api', 'public', 'ai_engine']\n    files = ['vercel.json', 'requirements.txt', '.gitignore']\n    \n    for folder in folders:\n        if os.path.isdir(folder):\n            print(f\"  вњ… {folder}/\")\n        else:\n            print(f\"  вљ пёЏ  {folder}/ (optional)\")\n    \n    for file in files:\n        if os.path.isfile(file):\n            print(f\"  вњ… {file}\")\n        else:\n            print(f\"  вќЊ {file}\")\n    \n    # Test API endpoints\n    print(\"\\nрџ”§ Starting Flask app...\")\n    print(\"   Go to: http://localhost:5000\")\n    print(\"   Login: admin / admin123\")\n    print(\"   Press Ctrl+C to stop\\n\")\n    \n    os.environ['FLASK_APP'] = 'api/index.py'\n    os.environ['FLASK_ENV'] = 'development'\n    \n    try:\n        from api.index import app\n        app.run(debug=True, port=5000)\n    except Exception as e:\n        print(f\"\\nвќЊ Error starting app: {e}\")\n        return 1\n    \n    return 0\n\nif __name__ == '__main__':\n    sys.exit(main())\n